def parse_kv_pairs(items: Optional[List[str]]) -> Dict[str, Any]:
    result = {}
    if not items:
        return result
    for item in items:
        if "=" not in item:
            raise ValueError(f"Invalid key=value pair: {item}")
        k, v = item.split("=", 1)
        k = k.strip()
        v = v.strip()
        if not k:
            raise ValueError(f"Empty key in pair: {item}")
        result[k] = v
    return result


def parse_json_or_kv(value: Optional[str]) -> Dict[str, Any]:
    if not value:
        return {}
    value = value.strip()
    if not value:
        return {}
    if value.startswith("{"):
        obj = json.loads(value)
        if not isinstance(obj, dict):
            raise ValueError("JSON config must be an object/dict")
        return obj
    raise ValueError("Config must be provided as JSON object string")


