def create_topics(admin: KafkaAdminClient, topics: List[str], partitions: int, replication_factor: int, configs: Dict[str, Any], if_not_exists: bool):
    new_topics = []
    for topic in topics:
        new_topics.append(
            NewTopic(
                name=topic,
                num_partitions=partitions,
                replication_factor=replication_factor,
                topic_configs=configs or None,
            )
        )
    return admin.create_topics(new_topics=new_topics, validate_only=False, timeout_ms=None, if_not_exists=if_not_exists)


def increase_partitions(admin: KafkaAdminClient, topic_partitions: Dict[str, int]):
    new_partitions = []
    for topic, total_count in topic_partitions.items():
        new_partitions.append(NewPartitions(topic, total_count))
    return admin.create_partitions(new_partitions=new_partitions, timeout_ms=None)


def alter_topic_configs(admin: KafkaAdminClient, topic: str, configs: Dict[str, Any], delete_keys: List[str]):
    resource = ConfigResource(ConfigResourceType.TOPIC, topic)
    config_entries = {}
    for k, v in configs.items():
        config_entries[k] = v
    for k in delete_keys:
        config_entries[k] = None
    return admin.alter_configs({resource: config_entries})


def describe_topic(admin: KafkaAdminClient, topic: str):
    return admin.describe_configs([ConfigResource(ConfigResourceType.TOPIC, topic)])


